import json
from pathlib import Path

REQUIRED_FIELDS = {
    "all": ["trace_id", "span_id", "name", "start_time",
            "attributes.claude.span_type", "attributes.claude.app_id",
            "attributes.claude.environment"],
    "claude.api_call": ["attributes.claude.model", "attributes.claude.region",
                         "attributes.claude.input_tokens"],
    "claude.response": ["attributes.claude.output_hash", "attributes.claude.output_tokens"],
    "claude.rag_retrieval": ["attributes.claude.rag.source_ids",
                              "attributes.claude.rag.chunk_ids"],
}

def get_nested(d: dict, dotted_key: str):
    keys = dotted_key.split(".")
    v = d
    for k in keys:
        if not isinstance(v, dict) or k not in v:
            return None
        v = v[k]
    return v

def validate_span_standards(span: dict) -> list[str]:
    """Return list of compliance violations. Empty list = compliant."""
    violations = []
    for field in REQUIRED_FIELDS["all"]:
        if get_nested(span, field) is None:
            violations.append(f"Missing required field: {field}")
    span_type = get_nested(span, "name")
    if span_type in REQUIRED_FIELDS:
        for field in REQUIRED_FIELDS[span_type]:
            if get_nested(span, field) is None:
                violations.append(f"Missing {span_type}-specific field: {field}")
    return violations

def audit_lineage_log(log_path: str = "logs/claude_lineage.jsonl") -> dict:
    total, compliant, all_violations = 0, 0, []
    for line in Path(log_path).read_text().splitlines():
        span = json.loads(line)
        violations = validate_span_standards(span)
        total += 1
        if not violations:
            compliant += 1
        else:
            all_violations.extend(violations)
    return {
        "total_spans": total,
        "compliant": compliant,
        "compliance_rate": round(compliant / total * 100, 2) if total else 0,
        "violations": all_violations[:20],  # first 20 for brevity
    }

import requests

ATLAS_BASE = "http://atlas-server:21000/api/atlas/v2"
ATLAS_AUTH = ("admin", "your-atlas-password")

def push_claude_lineage_to_atlas(trace_id: str, spans: list[dict]):
    """
    Push a completed trace as Atlas entities.
    Each claude_response span becomes a Process entity linking source datasets.
    """
    for span in spans:
        if span["name"] != "claude.response":
            continue
        attrs = span.get("attributes", {})
        source_ids = []
        for s in spans:
            if s["name"] == "claude.rag_retrieval":
                source_ids.extend(s.get("attributes", {}).get("claude.rag.source_ids", []))

        entity = {
            "entity": {
                "typeName": "Process",
                "attributes": {
                    "qualifiedName": f"claude_response/{trace_id}",
                    "name": f"Claude response ({attrs.get('claude.model', 'unknown')})",
                    "inputs": [{"typeName": "DataSet", "uniqueAttributes": {"qualifiedName": sid}}
                               for sid in source_ids],
                    "outputs": [{"typeName": "DataSet", "uniqueAttributes":
                                 {"qualifiedName": f"claude_output/{trace_id}"}}],
                    "description": f"AI response via {attrs.get('claude.app_id', '')}, "
                                   f"region={attrs.get('claude.region', '')}",
                },
            }
        }
        requests.post(f"{ATLAS_BASE}/entity", json=entity, auth=ATLAS_AUTH, timeout=10)
